#include <stdio.h>
#include <stdlib.h>

int find(int* parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

void unionSet(int* parent, int* rank, int x, int y) {
    int rootX = find(parent, x);
    int rootY = find(parent, y);
    if (rootX != rootY) {
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int* A = (int*)malloc(N * sizeof(int));
        int* B = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        int* parent = (int*)malloc(N * sizeof(int));
        int* rank = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
        int operations = 0;
        for (int i = 0; i < N; i++) {
            if (find(parent, A[i] - 1) != find(parent, B[i] - 1)) {
                unionSet(parent, rank, A[i] - 1, B[i] - 1);
                operations++;
            }
        }
        if (K == 1) {
            printf("%d\n", operations);
        } else {
            // count the number of optimal sequences
            int sequences = 1;
            for (int i = 1; i <= operations; i++) {
                sequences = (sequences * i) % (1000000007);
            }
            printf("%d %d\n", operations, sequences);
        }
        free(A);
        free(B);
        free(parent);
        free(rank);
    }
    return 0;
}

